<template>
  <div class="timer_fix">
    <van-cell title="选择日期区间" :value="date" @click="show = true" />
    <van-calendar
      color="#1989fa"
      v-model="show"
      type="range"
      @confirm="onConfirm"
      :show-confirm="false"
      :min-date="minDate"
      :max-date="maxDate"
    />
  </div>
</template>

<script>
export default {
  data() {
    return {
      date: "",
      show: false,
      minDate: new Date(2020, 0, 1),
      maxDate: new Date(2025, 0, 31),
    };
  },
  created() {
    let myDate = new Date();
    this.maxDate = new Date(
      myDate.getFullYear(),
      myDate.getMonth(),
      myDate.getDate()
    );
  },
  methods: {
    formatDate(date) {
      return `${date.getMonth() + 1}/${date.getDate()}`;
    },
    onConfirm(date) {
      const [start, end] = date;
      this.show = false;
      this.date = `${this.formatDate(start)} - ${this.formatDate(end)}`;
      // console.log(start, end);
      this.$emit("gettime", start, end);
    },
  },
};
</script>
<style lang="less">
.timer_fix {
  position: fixed;
  top: 46px;
  width: 100%;
  z-index: 100;
}
</style>