<template>
  <div class="myhistroyista">
    <van-sticky>
      <van-nav-bar
        title="我的委托"
        left-text="返回"
        right-text="按钮"
        left-arrow
        @click-left="onClickLeft"
        @click-right="onClickRight"
      />
    </van-sticky>
    <Timeselect @gettime="time" />
    <div class="sorll">
      <ul>
        <li v-for="(item, i) in list" :key="i">
          <Istacard :detail="item" :active="1" />
        </li>
        <li>
          <el-empty v-if="list.length === 0" :image-size="200"></el-empty>
        </li>
        <!-- <li>
          <van-loading color="#1989fa" />
        </li> -->
      </ul>
      <div class="isloading">
        <span>{{ loadingtext }}</span>
      </div>
    </div>
  </div>
</template>
<script>
import Istacard from "../../components/Istacard.vue";
import Timeselect from "../../components/time/Timeselect.vue";
import { getuserlist } from "../../utils/http/api.js";
import { mapState } from "vuex";
export default {
  name: "myista",
  components: {
    Istacard,
    Timeselect,
  },
  data() {
    return {
      type: "1",
      start_time: "",
      end_time: "",
      pageNo: 1,
      pageSize: 10,
      endScreen: false,
      isloading: false,
      list: [],
      loadingtext: "",
    };
  },
  computed: {
    ...mapState(["userid", "adminId"]),
  },
  watch: {
    endScreen: function (newval, old) {
      // console.log(newval);
      if (newval) {
        // get
        this.isloading = true;
        this.loadingtext = "加载中...";
        this.pageNo++;
        let info = {
          type: this.type,
          userId: this.userid * 1,
          adminId: this.adminId,
          startTime: this.start_time,
          endTime: this.end_time,
          pageNo: this.pageNo,
          pageSize: this.pageSize,
        };
        setTimeout(() => {
          this.getdata(info).then(
            (res) => {
              // console.log("页数", this.pageNo, res);
              // this.list.forEach((element) => {
              //   this.list.push("1");
              // });
              let len = res.data.data.list.length;
              if (len > 0) {
                res.data.data.list.map((item) => {
                  this.list.push(item);
                });
                this.loadingtext = "";
              } else if (len === 0) {
                this.pageNo--;
                this.loadingtext = "到底了！";
              }

              this.isloading = false;
            },
            (err) => {
              this.isloading = false;
              this.isloadingtext = "网络错误！";
            }
          );
        }, 2000);
      }
    },
  },
  mounted() {
    window.onscroll = () => {
      this.endScreen = this.screenCheck();
    };
  },
  beforeMount() {
    this.clearScroll();
  },
  created() {
    let date = new Date();
    // 当前时间
    this.end_time = date.getTime(date);
    // 一周前
    this.start_time = new Date(date - 3600 * 24 * 7 * 1000).getTime();

    let info = {
      type: this.type,
      userId: this.userid * 1,
      adminId: this.adminId,
      startTime: this.start_time,
      endTime: this.end_time,
      pageNo: this.pageNo,
      pageSize: this.pageSize,
    };

    this.getdata(info).then((res) => {
      res.data.data.list.map((item) => {
        this.list.push(item);
      });
    });
  },
  methods: {
    getdata(info) {
      return getuserlist(info);
    },
    time(start, end) {
      this.list = [];
      this.pageNo = 1;
      // console.log(start.getTime(start), end.getTime(end));
      this.start_time = start.getTime(start);
      this.end_time = end.getTime(end);
      let info = {
        type: this.type,
        userId: this.userid * 1,
        adminId: this.adminId,
        startTime: this.start_time,
        endTime: this.end_time,
        pageNo: this.pageNo,
        pageSize: this.pageSize,
      };

      this.getdata(info).then((res) => {
        res.data.data.list.map((item) => {
          this.list.push(item);
        });
      });
      // var nowdate = new Date();
      // var y = nowdate.getFullYear();
      // var m = nowdate.getMonth() + 1;
      // var d = nowdate.getDate();
      // var formatnowdate = y + "-" + m + "-" + d;
      // console.log(nowdate.getTime(nowdate));
    },
    // 检测屏幕是否到达底部的方法
    screenCheck() {
      if (this.isloading) return false;
      let screenH = Math.ceil(window.innerHeight + window.scrollY); // 屏幕高度+滚动高度
      let eleH = document.documentElement.scrollHeight; // 网页正文全文高
      // console.log(screenH, eleH);
      return screenH === eleH;
    },
    clearScroll() {
      window.removeEventListener("scroll", this.scrollHande);
    },
    onClickLeft() {
      this.$router.go(-1);
    },
    onClickRight() {},
  },
};
</script>

<style lang="less">
.myhistroyista {
  width: 7.5rem;
  background: @gray-2;
  .sorll {
    margin-top: 44px;
    overflow-y: scroll;
  }
  .isloading {
    height: 30px;
    display: flex;
    justify-content: center;
    align-items: center;
    span {
      font-size: 16px;
      font-weight: 500;
    }
  }
}
</style>